population.algorithm:
Greedy insertion with regret heuristic and fallback empty assign creation, trying best existing assign first then opening a new one if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type tryRes struct {
		idx     int
		delta   float64
		success bool
	}
	shipIdBase := total_ship
	for oi := range oris {
		bestTry := tryRes{-1, 1e18, false}
		worstTry := tryRes{-1, -1e18, false}
		secondBestDelta := 1e18
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assign := &dispatch.Assigns[ai]
			oldCost := assign.Cost
			ok := assign.AddShip(shipIdBase+oi, oris[oi], dess[oi])
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestTry.delta {
						bestTry.idx = ai
						bestTry.delta = delta
						bestTry.success = true
					}
					if delta > worstTry.delta {
						worstTry.delta = delta
						worstTry.idx = ai
						worstTry.success = true
					}
					if delta < secondBestDelta && ai != bestTry.idx {
						secondBestDelta = delta
					}
				}
				assign.RemoveShip(shipIdBase + oi)
				assign.GenRoute()
			}
		}
		regretValue := 0.0
		if bestTry.success && secondBestDelta < 1e17 {
			regretValue = secondBestDelta - bestTry.delta
		}
		useIdx := bestTry.idx
		fallbackNew := false
		if !bestTry.success || (dispatch.AssignsLen < MAXASSIGNS && regretValue > 500.0) {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAi := dispatch.AssignsLen
				ok := dispatch.Assigns[newAi].AddShip(shipIdBase+oi, oris[oi], dess[oi])
				if ok {
					dispatch.Assigns[newAi].GenRoute()
					if dispatch.Assigns[newAi].Cost >= 0 {
						dispatch.AssignsLen++
						useIdx = newAi
						fallbackNew = true
					} else {
						dispatch.Assigns[newAi].RemoveShip(shipIdBase + oi)
						dispatch.Assigns[newAi].GenRoute()
					}
				}
			}
		}
		if !fallbackNew {
			if bestTry.success {
				dispatch.Assigns[useIdx].AddShip(shipIdBase+oi, oris[oi], dess[oi])
				dispatch.Assigns[useIdx].GenRoute()
			} else {
				if dispatch.AssignsLen < MAXASSIGNS {
					newAi := dispatch.AssignsLen
					dispatch.Assigns[newAi].AddShip(shipIdBase+oi, oris[oi], dess[oi])
					dispatch.Assigns[newAi].GenRoute()
					if dispatch.Assigns[newAi].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[newAi].RemoveShip(shipIdBase + oi)
						dispatch.Assigns[newAi].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

