func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

population.algorithm:
Greedy randomized adaptive insertion with regret-based fallback and empty-slot prioritization.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx   int
		delta float64
		ok    bool
	}
	candidates := make([]cand, 0, MAXASSIGNS)

	for jj := range oris {
		bestIdx := -1
		bestDelta := 1e18
		secondBestDelta := 1e18

		candidates = candidates[:0]
		for ai := 0; ai < MAXASSIGNS; ai++ {
			var delta float64
			ok := false
			if ai < dispatch.AssignsLen || dispatch.Assigns[ai].StationsLen == 0 {
				backupID := dispatch.Assigns[ai].LastShipID
				backupCost := dispatch.Assigns[ai].Cost
				addOk := dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
				if addOk {
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						delta = dispatch.Assigns[ai].Cost - backupCost
						ok = true
					}
				}
				if ok {
					candidates = append(candidates, cand{idx: ai, delta: delta, ok: true})
					if delta < bestDelta {
						secondBestDelta = bestDelta
						bestDelta = delta
						bestIdx = ai
					} else if delta < secondBestDelta {
						secondBestDelta = delta
					}
				} else {
					dispatch.Assigns[ai].RemoveShip(total_ship + jj)
					dispatch.Assigns[ai].GenRoute()
				}
			}
		}

		regretThresh := 1e9
		if len(candidates) > 1 && secondBestDelta < 1e17 {
			regretThresh = secondBestDelta
		}

		finalIdx := -1
		if bestIdx >= 0 && (regretThresh-bestDelta) <= 2000 {
			finalIdx = bestIdx
		} else if bestIdx >= 0 && len(candidates) == 1 {
			finalIdx = bestIdx
		}

		if finalIdx < 0 {
			fallbackOrder := make([]int, 0, MAXASSIGNS)
			for i := 0; i < MAXASSIGNS; i++ {
				fallbackOrder = append(fallbackOrder, i)
			}
			for _, ai := range fallbackOrder {
				backupCost := dispatch.Assigns[ai].Cost
				addOk := dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
				if addOk {
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						finalIdx = ai
						break
					} else {
						dispatch.Assigns[ai].RemoveShip(total_ship + jj)
						dispatch.Assigns[ai].GenRoute()
					}
				}
			}
		}

		if finalIdx >= 0 {
			if finalIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			for ai := 0; ai < MAXASSIGNS; ai++ {
				if dispatch.Assigns[ai].StationsLen == 0 {
					dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						if ai >= dispatch.AssignsLen {
							dispatch.AssignsLen = ai + 1
						}
						break
					} else {
						dispatch.Assigns[ai].RemoveShip(total_ship + jj)
						dispatch.Assigns[ai].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

