Regret-based greedy insertion with weighted penalty for time window tightness and distance increase, prioritizing slots that maximize combined improvement while maintaining feasibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	n := len(oris)
	assignsCap := dispatch.AssignsLen
	timeWeight := 0.7
	distanceWeight := 0.3
	for i := 0; i < n; i++ {
		bestIdx := -1
		bestScore := -1e308
		secondBestScore := -1e308
		inserted := false
		type candidateInfo struct {
			idx       int
			delta     float64
			tightness float64
		}
		var candidates []candidateInfo
		for ai := 0; ai < assignsCap; ai++ {
			oldCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(total_ship+i, oris[i], dess[i])
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					var maxTightness float64
					stations := dispatch.Assigns[ai].Stations
					for j := 0; j < len(stations); j++ {
						windowWidth := stations[j].TimeEnd - stations[j].TimeStart
						if windowWidth <= 0 {
							maxTightness = 1e9
						} else {
							tight := 1.0 / float64(windowWidth+1)
							if tight > maxTightness {
								maxTightness = tight
							}
						}
					}
					score := -(delta*distanceWeight + maxTightness*timeWeight)
					candidates = append(candidates, candidateInfo{idx: ai, delta: delta, tightness: maxTightness})
					if score > bestScore {
						secondBestScore = bestScore
						bestScore = score
						bestIdx = ai
					} else if score > secondBestScore {
						secondBestScore = score
					}
				}
				dispatch.Assigns[ai].RemoveShip(total_ship + i)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		regret := bestScore - secondBestScore
		finalChoice := bestIdx
		if len(candidates) > 0 && regret < 0.01 && bestIdx >= 0 {
			earlyBestIdx := -1
			earlyArr := 1<<31 - 1
			for _, cand := range candidates {
				tempOk := dispatch.Assigns[cand.idx].AddShip(total_ship+i, oris[i], dess[i])
				if tempOk {
					dispatch.Assigns[cand.idx].GenRoute()
					if dispatch.Assigns[cand.idx].Cost >= 0 {
						var curTime int
						if sl := len(dispatch.Assigns[cand.idx].Stations); sl > 0 {
							curTime = dispatch.Assigns[cand.idx].Stations[sl-1].TimeEnd
						}
						if curTime < earlyArr {
							earlyArr = curTime
							earlyBestIdx = cand.idx
						}
					}
					dispatch.Assigns[cand.idx].RemoveShip(total_ship + i)
					dispatch.Assigns[cand.idx].GenRoute()
				}
			}
			if earlyBestIdx >= 0 {
				finalChoice = earlyBestIdx
			}
		}
		if finalChoice >= 0 {
			ok := dispatch.Assigns[finalChoice].AddShip(total_ship+i, oris[i], dess[i])
			if ok {
				dispatch.Assigns[finalChoice].GenRoute()
				if dispatch.Assigns[finalChoice].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[finalChoice].RemoveShip(total_ship + i)
					dispatch.Assigns[finalChoice].GenRoute()
					finalChoice = -1
				}
			}
		}
		if !inserted {
			bestFeasibleIdx := -1
			bestWait := 1e308
			for ai := 0; ai < assignsCap; ai++ {
				st := dispatch.Assigns[ai].StationCurrent
				travelToOri := cal_dis(st, oris[i])
				arrAtOri := travelToOri
				if arrAtOri < float64(oris[i].TimeStart) {
					arrAtOri = float64(oris[i].TimeStart)
				}
				if arrAtOri <= float64(oris[i].TimeEnd) {
					waitTime := arrAtOri - travelToOri
					if waitTime < bestWait {
						bestWait = waitTime
						bestFeasibleIdx = ai
					}
				}
			}
			if bestFeasibleIdx >= 0 {
				ok := dispatch.Assigns[bestFeasibleIdx].AddShip(total_ship+i, oris[i], dess[i])
				if ok {
					dispatch.Assigns[bestFeasibleIdx].GenRoute()
					if dispatch.Assigns[bestFeasibleIdx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[bestFeasibleIdx].RemoveShip(total_ship + i)
						dispatch.Assigns[bestFeasibleIdx].GenRoute()
					}
				}
			}
			if !inserted && assignsCap < MAXASSIGNS {
