	}
	for i := 0; i < len(orderIndices); i++ {
		for j := i + 1; j < len(orderIndices); j++ {
			twi := oris[orderIndices[i]].TimeEnd - oris[orderIndices[i]].TimeStart
			twj := oris[orderIndices[j]].TimeEnd - oris[orderIndices[j]].TimeStart
			if twi > twj {
				orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
			}
		}
	}
	for _, idx := range orderIndices {
		bestScore := math.MaxFloat64
		bestVehicle := -1
		inserted := false
		ori := oris[idx]
		des := dess[idx]
		for v := 0; v < MAXASSIGNS; v++ {
