				continue
			}
			prevCost := dispatch.Assigns[v].Cost
			if prevCost < 0 {
				continue
			}
			curSt := dispatch.Assigns[v].StationCurrent
			addDist := cal_dis(curSt, ori) + cal_dis(ori, des)
			timeUrgency := float64(ori.TimeEnd - ori.TimeStart)
			if timeUrgency <= 0 {
