func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx  int
		cost float64
	}
	for jj := range oris {
		bestIdx := -1
		bestCostDelta := 1e308
		secondBestCostDelta := 1e308
		candidates := make([]candidate, 0, dispatch.AssignsLen+1)

		for ii := 0; ii <= dispatch.AssignsLen && ii < MAXASSIGNS; ii++ {
			assignCopy := dispatch.Assigns[ii]
			ok := assignCopy.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				assignCopy.GenRoute()
				if assignCopy.Cost >= 0 {
					delta := assignCopy.Cost - dispatch.Assigns[ii].Cost
					if delta < bestCostDelta {
						secondBestCostDelta = bestCostDelta
						bestCostDelta = delta
						bestIdx = ii
					} else if delta < secondBestCostDelta {
						secondBestCostDelta = delta
					}
					candidates = append(candidates, candidate{idx: ii, cost: delta})
				}
				assignCopy.RemoveShip(total_ship + jj)
				assignCopy.GenRoute()
			}
		}

		inserted := false
		if bestIdx != -1 {
			regret := secondBestCostDelta - bestCostDelta
			if len(candidates) > 1 && regret < 0 {
				regret = 0
			}

			pickIdx := bestIdx
			if len(candidates) > 3 && regret < 1000 {
				pickIdx = candidates[0].idx
				minMarginal := candidates[0].cost
				for _, c := range candidates {
					if c.cost < minMarginal {
						minMarginal = c.cost
						pickIdx = c.idx
					}
				}
			} else {
				pickIdx = bestIdx
			}

			if pickIdx < dispatch.AssignsLen || (pickIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS) {
				ok := dispatch.Assigns[pickIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[pickIdx].GenRoute()
					if dispatch.Assigns[pickIdx].Cost >= 0 {
						inserted = true
						if pickIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
					} else {
						dispatch.Assigns[pickIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[pickIdx].GenRoute()
					}
				}
			}
		}

		if !inserted {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}

		if !inserted {
			for ii := 0; ii < dispatch.AssignsLen && ii < MAXASSIGNS; ii++ {
				ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						inserted = true
						break
					} else {
						dispatch.Assigns[ii].RemoveShip(total_ship + jj)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

